const query = $json.query || {};

const clusters = {
  silver:  { testId: '7719640', slo: 0.995 },
  emerald: { testId: '7719620', slo: 0.995 },
  gold:    { testId: '7719621', slo: 0.9995 },
  golddr:  { testId: '7719622', slo: 0.9995 },
  'gold-ha': { primary: '7719621', secondary: '7719622', slo: 0.9995 },
};

const testIdToCluster = {
  '7719640': 'silver',
  '7719620': 'emerald',
  '7719621': 'gold',
  '7719622': 'golddr',
};

let cluster = query.cluster ? String(query.cluster).toLowerCase() : '';
if (!cluster && query.test_id && testIdToCluster[String(query.test_id)]) {
  cluster = testIdToCluster[String(query.test_id)];
}
if (!clusters[cluster]) cluster = 'silver';

let days = parseInt(String(query.days || '30'), 10);
if (!Number.isFinite(days) || days < 1) days = 30;
if (days > 3650) days = 3650;

const slo = (query.slo !== undefined && String(query.slo).trim() !== '')
  ? Number(query.slo)
  : Number(clusters[cluster].slo);

const safeCluster = cluster.replace(/'/g, "''");
const sql = [
  'SELECT day, value_minutes',
  'FROM public.error_budget_daily',
  "WHERE cluster = '" + safeCluster + "'",
  '  AND day >= (current_date - (' + days + '::int - 1))',
  'ORDER BY day;'
].join('\n');

return [{ json: { cluster, days, slo, sql } }];

const rows = $input.all().filter((item) => item.json && item.json.day !== undefined);

const data = rows.map((item) => {
  const rawDay = item.json.day;
  const day = rawDay instanceof Date
    ? rawDay.toISOString().slice(0, 10)
    : String(rawDay).slice(0, 10);
  return {
    timestamp: day + 'T00:00:00.000Z',
    value: Number(item.json.value_minutes),
  };
});

return [{ json: { data } }];

